cd /tmp/sv-df0299924eb74bb1b71c595e4925ebfb
# Look up the actual functions at those addresses using nm + sorting
# Find function containing 0x2f4b20 and 0x2f4c84
nm -C --defined-only mono_debug.so 2>/dev/null | awk '$2 ~ /[tTwW]/' | sort | awk -v addr1=0x2f4b20 -v addr2=0x2f4c84 '
{
  a = strtonum("0x"$1)
  if (a <= strtonum(addr1)) { func1 = $0; fa1 = a }
  if (a <= strtonum(addr2)) { func2 = $0; fa2 = a }
}
END {
  print "0x2f4b20 -> " func1 " (offset +" strtonum(addr1)-fa1 ")"
  print "0x2f4c84 -> " func2 " (offset +" strtonum(addr2)-fa2 ")"
}'

