cd /tmp/sv-df0299924eb74bb1b71c595e4925ebfb
# Find local symbols near the target addresses in the debug file
nm -n mono_debug.so | awk '
BEGIN { target[1]=0x2f4b20; target[2]=0x2f4c84 }
{
  a = strtonum("0x"$1)
  for (i=1; i<=2; i++) {
    if (a <= target[i]) { prev[i] = $0; pa[i] = a }
    if (a > target[i] && !done[i]) { 
      printf "0x%x:\n  before: %s\n  after:  %s\n\n", target[i], prev[i], $0
      done[i]=1
    }
  }
}' | head -20

